import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cost.BagEstimate;
import org.junit.jupiter.api.Test;

class OmniSketchSurfaceEstimateTest {

	@Test
	void preservesCompleteOmniSurfaceForCostingAndPlanning() {
		OmniWitnessSet witnesses = OmniWitnessSet.fromSortedUnsigned(new long[] { 7L, 11L },
				new double[] { 3.0d, 5.0d }, 2, 0.25d, 0.80d,
				OmniWitnessSet.FallbackReason.SAMPLE_LOSS, 16.0d)
				.withSourceKind(OmniWitnessSet.SourceKind.SUBJECT_COHORT);
		OmniSketchBindingEvidence binding = new OmniSketchBindingEvidence("encounter", 32.0d, 8.0d, 2,
				witnesses, OmniWitnessSet.SourceKind.SUBJECT_COHORT, "STATEMENT", "subject");
		OmniSketchStepEvidence step = new OmniSketchStepEvidence("bridge-probe", "encounter", "drug",
				64.0d, 12.0d, 9.0d, 4, 3, 2, 0.25d, "SAMPLE_LOSS",
				OmniWitnessSet.SourceKind.SUBJECT_COHORT, false, "EDGE_FORWARD", "lmdbValueId");

		OmniSketchSurfaceEstimate estimate = new OmniSketchSurfaceEstimate(9.0d, 4.0d, 16.0d, 21.0d,
				0.80d, 0.25d, false, "SAMPLE_LOSS", 16.0d, "omni-join-estimator",
				"bridge-chain", "lmdbValueId",
				Map.of("plannedOmniFallbackReason", "SAMPLE_LOSS"),
				Map.of("plannedOmniProbeWitnesses", 3.0d),
				Map.of("encounter", binding),
				List.of(step));

		assertEquals(9.0d, estimate.selectedRows(), 0.0d);
		assertEquals(9.0d, estimate.calibratedRows(), 0.0d);
		assertEquals(4.0d, estimate.lowerBoundRows(), 0.0d);
		assertEquals(16.0d, estimate.upperBoundRows(), 0.0d);
		assertEquals(21.0d, estimate.workRows(), 0.0d);
		assertEquals(0.80d, estimate.confidence(), 0.0d);
		assertEquals(0.25d, estimate.samplingProbability(), 0.0d);
		assertEquals("SAMPLE_LOSS", estimate.fallbackReason());
		assertEquals(16.0d, estimate.minimumDetectableRows(), 0.0d);
		assertEquals("bridge-chain", estimate.surfaceKind());
		assertEquals("lmdbValueId", estimate.predicateKeyKind());
		assertSame(witnesses, estimate.bindings().get("encounter").witnesses());
		assertEquals(OmniWitnessSet.SourceKind.SUBJECT_COHORT, estimate.bindings().get("encounter").sourceKind());
		assertEquals("drug", estimate.steps().get(0).outputBindingName());
		assertEquals(2, estimate.steps().get(0).outputWitnesses());
		assertEquals("SAMPLE_LOSS", estimate.toStringMetrics().get("plannedOmniFallbackReason"));
		assertEquals(9.0d, estimate.toDoubleMetrics().get("plannedOmniJoinSurfaceRows"), 0.0d);
		assertEquals(16.0d, estimate.toDoubleMetrics().get("plannedOmniJoinSurfaceUpperBoundRows"), 0.0d);
		assertEquals(0.80d, estimate.toDoubleMetrics().get("plannedSketchConfidence"), 0.0d);
		assertEquals(2.0d, estimate.toDoubleMetrics().get("plannedOmniBindingWitnesses"), 0.0d);

		BagEstimate bag = estimate.toBagEstimate(Set.of("encounter", "drug"));
		assertEquals(9.0d, bag.rows(), 0.0d);
		assertEquals(21.0d, bag.workRows(), 0.0d);
		assertEquals(0.80d, bag.confidence(), 0.0d);
		assertTrue(bag.hasBindingEvidence());

		OmniSketchSurfaceEstimate.CostInputs costInputs = estimate.toCostInputs();
		assertEquals(9.0d, costInputs.rows(), 0.0d);
		assertEquals(21.0d, costInputs.workRows(), 0.0d);
		assertEquals(0.80d, costInputs.confidence(), 0.0d);
		assertEquals(2.0d, costInputs.evidenceCount(), 0.0d);

		FactorCostEstimate factorCost = new FactorCostEstimate(estimate.workRows(), estimate.selectedRows(),
				Map.of(), estimate.toDoubleMetrics());
		assertEquals(costInputs.rowQErrorMax(), factorCost.getEstimateVector().rowQErrorMax(), 0.0d);
		assertEquals(costInputs.workQErrorMax(), factorCost.getEstimateVector().workQErrorMax(), 0.0d);
		assertEquals(costInputs.uncertaintyRows(), factorCost.getEstimateVector().uncertaintyRows(), 0.0d);
		assertEquals(costInputs.confidence(), factorCost.getEstimateVector().confidence(), 0.0d);
		assertEquals(costInputs.evidenceCount(), factorCost.getEstimateVector().evidenceCount(), 0.0d);
	}

	@Test
	void composesEveryBridgeSurfaceWithoutDiscardingEvidence() {
		OmniWitnessSet leftWitnesses = OmniWitnessSet.fromSortedUnsigned(new long[] { 1L }, new double[] { 4.0d },
				1, 0.5d, 0.8d, OmniWitnessSet.FallbackReason.NONE, 2.0d);
		OmniWitnessSet rightWitnesses = OmniWitnessSet.fromSortedUnsigned(new long[] { 2L }, new double[] { 6.0d },
				1, 0.25d, 0.7d, OmniWitnessSet.FallbackReason.SAMPLE_LOSS, 4.0d);
		OmniSketchSurfaceEstimate left = new OmniSketchSurfaceEstimate(8.0d, 6.0d, 10.0d, 12.0d, 0.8d, 0.5d,
				false, "none", 2.0d, "left", "bridge-probe", "predicate", Map.of(), Map.of(),
				Map.of("left", new OmniSketchBindingEvidence("left", 8.0d, 2.0d, 1, leftWitnesses,
						OmniWitnessSet.SourceKind.BASE, "edge", "left")),
				List.of(new OmniSketchStepEvidence("bridge-probe", "root", "left", 8.0d, 8.0d, 8.0d,
						1, 1, 1, 0.5d, "none", OmniWitnessSet.SourceKind.BASE, false, "edge", "left")));
		OmniSketchSurfaceEstimate right = new OmniSketchSurfaceEstimate(12.0d, 8.0d, 18.0d, 20.0d, 0.7d, 0.25d,
				false, "SAMPLE_LOSS", 4.0d, "right", "bridge-probe", "predicate", Map.of(), Map.of(),
				Map.of("right", new OmniSketchBindingEvidence("right", 12.0d, 3.0d, 1, rightWitnesses,
						OmniWitnessSet.SourceKind.SUBJECT_COHORT, "edge", "right")),
				List.of(new OmniSketchStepEvidence("bridge-probe", "root", "right", 12.0d, 12.0d, 12.0d,
						1, 1, 1, 0.25d, "SAMPLE_LOSS", OmniWitnessSet.SourceKind.SUBJECT_COHORT, false,
						"edge", "right")));

		OmniSketchSurfaceEstimate composed = OmniSketchSurfaceEstimate.compose(List.of(left, right), 24.0d, 32.0d,
				"optional-multi-bridge", "optional-multi-bridge");

		assertEquals(Set.of("left", "right"), composed.bindings().keySet());
		assertEquals(2, composed.steps().size());
		assertSame(leftWitnesses, composed.bindings().get("left").witnesses());
		assertSame(rightWitnesses, composed.bindings().get("right").witnesses());
		assertEquals(0.25d, composed.samplingProbability(), 0.0d);
		assertEquals("SAMPLE_LOSS", composed.fallbackReason());
		assertEquals(4.0d, composed.minimumDetectableRows(), 0.0d);
	}
}
